#include <stdio.h>
#include <string.h>

int countLetters(int num) {
    if (num < 10) {
        char *ones[] = {"", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"};
        return strlen(ones[num]);
    }
    if (num < 20) {
        char *teens[] = {"ten", "eleven", "twelve", "thirteen", "fourteen", "fifteen", "sixteen", "seventeen", "eighteen", "nineteen"};
        return strlen(teens[num - 10]);
    }
    if (num < 100) {
        char *tens[] = {"", "", "twenty", "thirty", "forty", "fifty", "sixty", "seventy", "eighty", "ninety"};
        if (num % 10 == 0) {
            return strlen(tens[num / 10]);
        } else {
            return strlen(tens[num / 10]) + strlen(ones[num % 10]);
        }
    }
    if (num < 1000) {
        if (num % 100 == 0) {
            char *ones[] = {"", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"};
            return strlen(ones[num / 100]) + strlen("hundred");
        } else {
            char *ones[] = {"", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"};
            return strlen(ones[num / 100]) + strlen("hundredand") + countLetters(num % 100);
        }
    }
    return 0;
}

